INSERT INTO reservations (id,user_id,rental_type_id,reservation_date,created_at)
SELECT
    uuid_generate_v4(),
    ('10000000-0000-0000-0000-0000000000' || LPAD(((gs % 20)+2)::text,2,'0'))::uuid,
    ('20000000-0000-0000-0000-0000000000' || LPAD(((gs % 10)+1)::text,2,'0'))::uuid,
    DATE '2026-05-01' + gs,
    CURRENT_TIMESTAMP
FROM generate_series(0,99) gs;